def find_first_puerto_rican_miss_universe(winners):
    for winner in winners:
        if winner.get('year') >= 1990 and winner.get('country') == 'Puerto Rico' and winner.get('title') == 'Miss Universe':
            return winner
    return None

# Example usage:
winners = [
    {'year': 1970, 'country': 'Puerto Rico', 'title': 'Miss Universe'},
    {'year': 1985, 'country': 'Puerto Rico', 'title': 'Miss Universe'},
    {'year': 1993, 'country': 'Puerto Rico', 'title': 'Miss Universe'}
]
print(find_first_puerto_rican_miss_universe(winners))
# Output: {'year': 1993, 'country': 'Puerto Rico', 'title': 'Miss Universe'}
